const apiBase=window.location.origin,websitesEl=document.getElementById("websiteList"),createResult=document.getElementById("createResult"),crawlResult=document.getElementById("crawlResult"),embedSnippet=document.getElementById("embedSnippet");async function fetchWebsites(){const res=await fetch(`${apiBase}/api/websites`),websites=await res.json();Array.isArray(websites)?websitesEl.innerHTML=websites.map(ws=>`\n    <div class="website">\n      <strong>${ws.domain}</strong> <span style="color:#6b7280;">${ws.id}</span>\n      <div>Embed code:\n        <pre>${createEmbedSnippet(ws.id)}</pre>\n      </div>\n      <div>Last crawled: ${ws.last_crawled_at||"never"}</div>\n    </div>\n  `).join(""):websitesEl.innerText="Failed to load websites."}function createEmbedSnippet(websiteId){return`<script>\nwindow.AI_CHATBOT_WIDGET_CONFIG = {\n  websiteId: '${websiteId}',\n  apiUrl: '${apiBase}/api/chat'\n};\n<\/script>\n<script type="module" src="${apiBase}/widget/embed.js"><\/script>`}async function createWebsite(){const domain=document.getElementById("domain").value.trim(),startUrl=document.getElementById("startUrl").value.trim();if(!domain&&!startUrl)return void(createResult.innerText="Provide a domain or a start URL.");const body=domain?{domain:domain}:{startUrl:startUrl},res=await fetch(`${apiBase}/api/websites`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)}),data=await res.json();res.ok?(createResult.innerText=`Created website ${data.website.domain} (${data.website.id})`,embedSnippet.innerText=data.embedCode,await fetchWebsites()):createResult.innerText=data.error||"Failed to create website."}async function crawlWebsite(){const websiteId=document.getElementById("crawlWebsiteId").value.trim(),startUrl=document.getElementById("crawlUrl").value.trim();if(!websiteId)return void(crawlResult.innerText="Website ID is required.");const res=await fetch(`${apiBase}/api/crawl`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({website_id:websiteId,start_url:startUrl||void 0})}),data=await res.json();res.ok?(crawlResult.innerText=`Crawled ${data.crawled} page(s).`,await fetchWebsites()):crawlResult.innerText=data.error||"Crawl failed."}window.addEventListener("load",async()=>{document.getElementById("createWebsite").addEventListener("click",createWebsite),document.getElementById("startCrawl").addEventListener("click",crawlWebsite),await fetchWebsites()});